export type QASeverity = 'critical' | 'high' | 'medium' | 'low' | 'info';
export type QAProduct = 'MSIT' | 'IMT' | 'DRM';

export interface QAFinding {
  id: string;
  product: QAProduct;
  repo: string;
  branch: string;
  severity: QASeverity;
  title: string;
  /** The identified issue and how to reproduce it. */
  issue: string;
  /** The actual result observed. */
  actual: string;
  /** The expected result. */
  expected: string;
  location: string;
  author: string;
}

export interface QAServiceSummary {
  repo: string;
  product: QAProduct;
  stack: string;
  branchesAudited: string;
  testRun: string;
}

